select distinct r.* from platform_resource r inner join platform_role_resource rr on rr.resource_id = r.id inner join platform_resource_group g on g.id = r.group_id WHERE g.id = #{groupId} and rr.role_id IN
#{roleId}
order by r.show_order asc

